import React, { useEffect, useState } from 'react';

function InicioForm({ onContinue }) {
  const [entrevistadores, setEntrevistadores] = useState([]);
  const [entrevistadorId, setEntrevistadorId] = useState('');
  const [nuevoEntrevistador, setNuevoEntrevistador] = useState('');
  const [postulante, setPostulante] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    fetch('http://localhost/sistema-entrevistas/backend/api/listar_entrevistadores.php')
      .then(res => res.json())
      .then(data => setEntrevistadores(data))
      .catch(err => {
        console.error("Error al cargar entrevistadores:", err);
        setError("No se pudieron cargar los entrevistadores.");
      });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!postulante.trim()) {
      setError('Debes escribir el nombre del postulante.');
      return;
    }

    try {
      let entrevistadorFinalId = entrevistadorId;

      // Si no hay entrevistadores o usuario escribe uno nuevo
      if (entrevistadores.length === 0 || nuevoEntrevistador.trim()) {
        const res = await fetch('http://localhost/sistema-entrevistas/backend/api/crear_entrevistador.php', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ nombre: nuevoEntrevistador.trim() })
        });
        const data = await res.json();
        if (data.status === 'ok') {
          entrevistadorFinalId = data.id;
        } else {
          setError('No se pudo crear el entrevistador.');
          return;
        }
      }

      // Crear postulante
      const response = await fetch('http://localhost/sistema-entrevistas/backend/api/crear_postulante.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nombre: postulante })
      });

      const result = await response.json();
      if (result.status === 'ok') {
        onContinue(entrevistadorFinalId, result.id);
      } else {
        setError('Error al registrar el postulante.');
      }

    } catch (err) {
      console.error(err);
      setError('No se pudo conectar al backend.');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>Inicio de entrevista</h2>

      {entrevistadores.length > 0 ? (
        <>
          <label>Selecciona al entrevistador:</label>
          <select
            value={entrevistadorId}
            onChange={(e) => setEntrevistadorId(e.target.value)}
            required
            style={{ width: '100%', padding: '8px', marginBottom: '10px' }}
          >
            <option value="">-- Selecciona --</option>
            {entrevistadores.map((e) => (
              <option key={e.id} value={e.id}>{e.nombre}</option>
            ))}
          </select>

          <p style={{ fontSize: '0.9em' }}>¿No está en la lista? Escribe uno nuevo:</p>
          <input
            type="text"
            value={nuevoEntrevistador}
            onChange={(e) => setNuevoEntrevistador(e.target.value)}
            placeholder="Nuevo entrevistador (opcional)"
            style={{ width: '100%', padding: '8px', marginBottom: '15px' }}
          />
        </>
      ) : (
        <>
          <label>Nombre del entrevistador:</label>
          <input
            type="text"
            value={nuevoEntrevistador}
            onChange={(e) => setNuevoEntrevistador(e.target.value)}
            placeholder="Ej. Ana Ramírez"
            required
            style={{ width: '100%', padding: '8px', marginBottom: '15px' }}
          />
        </>
      )}

      <label>Nombre del postulante:</label>
      <input
        type="text"
        value={postulante}
        onChange={(e) => setPostulante(e.target.value)}
        placeholder="Ej. Juan Pérez"
        required
        style={{ width: '100%', padding: '8px', marginBottom: '15px' }}
      />

      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button type="submit" style={{
        padding: '10px 20px',
        backgroundColor: '#007bff',
        color: 'white',
        border: 'none',
        borderRadius: '8px',
        cursor: 'pointer'
      }}>
        Comenzar entrevista
      </button>
    </form>
  );
}

export default InicioForm;
